function flat(arr, depth = 1) {
  if (depth <= 0) return arr.slice();
  const res = [];
  for (const item of arr) {
    if (Array.isArray(item)) {
      res.push(...flat(item, depth - 1));
    } else {
      res.push(item);
    }
  }
  return res;
}

