        .then(value => {
          results[idx] = { status: 'fulfilled', value };
        })
        .catch(reason => {
          results[idx] = { status: 'rejected', reason };
        })
        .finally(() => {
          completed++;
          if (completed === len) resolve(results);
        });
    });
